import{_ as t,c as e,o as s,a}from"./app.204b65b3.js";const u=JSON.parse('{"title":"07.RESTful","description":"","frontmatter":{},"headers":[{"level":2,"title":"1、RESTful 简介","slug":"_1、restful-简介","link":"#_1、restful-简介","children":[{"level":3,"title":"a>资源","slug":"a-资源","link":"#a-资源","children":[]},{"level":3,"title":"b>资源的表述","slug":"b-资源的表述","link":"#b-资源的表述","children":[]},{"level":3,"title":"c>状态转移","slug":"c-状态转移","link":"#c-状态转移","children":[]}]},{"level":2,"title":"2、RESTful 的实现","slug":"_2、restful-的实现","link":"#_2、restful-的实现","children":[]},{"level":2,"title":"3、HiddenHttpMethodFilter","slug":"_3、hiddenhttpmethodfilter","link":"#_3、hiddenhttpmethodfilter","children":[{"level":3,"title":"a>当前请求的请求方式必须为 post","slug":"a-当前请求的请求方式必须为-post","link":"#a-当前请求的请求方式必须为-post","children":[]},{"level":3,"title":"b>当前请求必须传输请求参数_method","slug":"b-当前请求必须传输请求参数-method","link":"#b-当前请求必须传输请求参数-method","children":[]}]}],"relativePath":"articles/02-后端/Java/05-SpringMVC/07.RESTful.md"}'),l={name:"articles/02-后端/Java/05-SpringMVC/07.RESTful.md"},n=a(`<h1 id="_07-restful" tabindex="-1">07.RESTful <a class="header-anchor" href="#_07-restful" aria-hidden="true">#</a></h1><h2 id="_1、restful-简介" tabindex="-1">1、RESTful 简介 <a class="header-anchor" href="#_1、restful-简介" aria-hidden="true">#</a></h2><p>REST：<strong>Re</strong>presentational <strong>S</strong>tate <strong>T</strong>ransfer，表现层资源状态转移。</p><h3 id="a-资源" tabindex="-1">a&gt;资源 <a class="header-anchor" href="#a-资源" aria-hidden="true">#</a></h3><p>资源是一种看待服务器的方式，即，将服务器看作是由很多离散的资源组成。每个资源是服务器上一个可命名的抽象概念。因为资源是一个抽象的概念，所以它不仅仅能代表服务器文件系统中的一个文件、数据库中的一张表等等具体的东西，可以将资源设计的要多抽象有多抽象，只要想象力允许而且客户端应用开发者能够理解。与面向对象设计类似，资源是以名词为核心来组织的，首先关注的是名词。一个资源可以由一个或多个 URI 来标识。URI 既是资源的名称，也是资源在 Web 上的地址。对某个资源感兴趣的客户端应用，可以通过资源的 URI 与其进行交互。</p><h3 id="b-资源的表述" tabindex="-1">b&gt;资源的表述 <a class="header-anchor" href="#b-资源的表述" aria-hidden="true">#</a></h3><p>资源的表述是一段对于资源在某个特定时刻的状态的描述。可以在客户端-服务器端之间转移（交换）。资源的表述可以有多种格式，例如 HTML/XML/JSON/纯文本/图片/视频/音频等等。资源的表述格式可以通过协商机制来确定。请求-响应方向的表述通常使用不同的格式。</p><h3 id="c-状态转移" tabindex="-1">c&gt;状态转移 <a class="header-anchor" href="#c-状态转移" aria-hidden="true">#</a></h3><p>状态转移说的是：在客户端和服务器端之间转移（transfer）代表资源状态的表述。通过转移和操作资源的表述，来间接实现操作资源的目的。</p><h2 id="_2、restful-的实现" tabindex="-1">2、RESTful 的实现 <a class="header-anchor" href="#_2、restful-的实现" aria-hidden="true">#</a></h2><p>具体说，就是 HTTP 协议里面，四个表示操作方式的动词：GET、POST、PUT、DELETE。</p><p>它们分别对应四种基本操作：GET 用来获取资源，POST 用来新建资源，PUT 用来更新资源，DELETE 用来删除资源。</p><p>REST 风格提倡 URL 地址使用统一的风格设计，从前到后各个单词使用斜杠分开，不使用问号键值对方式携带请求参数，而是将要发送给服务器的数据作为 URL 地址的一部分，以保证整体风格的一致性。</p><table><thead><tr><th>操作</th><th>传统方式</th><th>REST 风格</th></tr></thead><tbody><tr><td>查询操作</td><td>getUserById?id=1</td><td>user/1--&gt;get 请求方式</td></tr><tr><td>保存操作</td><td>saveUser</td><td>user--&gt;post 请求方式</td></tr><tr><td>删除操作</td><td>deleteUser?id=1</td><td>user/1--&gt;delete 请求方式</td></tr><tr><td>更新操作</td><td>updateUser</td><td>user--&gt;put 请求方式</td></tr></tbody></table><h2 id="_3、hiddenhttpmethodfilter" tabindex="-1">3、HiddenHttpMethodFilter <a class="header-anchor" href="#_3、hiddenhttpmethodfilter" aria-hidden="true">#</a></h2><p>由于浏览器只支持发送 get 和 post 方式的请求，那么该如何发送 put 和 delete 请求呢？</p><p>SpringMVC 提供了 <strong>HiddenHttpMethodFilter</strong> 帮助我们<strong>将 POST 请求转换为 DELETE 或 PUT 请求</strong></p><p><strong>HiddenHttpMethodFilter</strong> 处理 put 和 delete 请求的条件：</p><h3 id="a-当前请求的请求方式必须为-post" tabindex="-1">a&gt;当前请求的请求方式必须为 post <a class="header-anchor" href="#a-当前请求的请求方式必须为-post" aria-hidden="true">#</a></h3><h3 id="b-当前请求必须传输请求参数-method" tabindex="-1">b&gt;当前请求必须传输请求参数_method <a class="header-anchor" href="#b-当前请求必须传输请求参数-method" aria-hidden="true">#</a></h3><p>满足以上条件，<strong>HiddenHttpMethodFilter</strong> 过滤器就会将当前请求的请求方式转换为请求参数_method 的值，因此请求参数_method 的值才是最终的请求方式</p><p>在 web.xml 中注册<strong>HiddenHttpMethodFilter</strong></p><div class="language-xml"><button title="Copy Code" class="copy"></button><span class="lang">xml</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">filter</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">filter-name</span><span style="color:#89DDFF;">&gt;</span><span style="color:#A6ACCD;">HiddenHttpMethodFilter</span><span style="color:#89DDFF;">&lt;/</span><span style="color:#F07178;">filter-name</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">filter-class</span><span style="color:#89DDFF;">&gt;</span><span style="color:#A6ACCD;">org.springframework.web.filter.HiddenHttpMethodFilter</span><span style="color:#89DDFF;">&lt;/</span><span style="color:#F07178;">filter-class</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#89DDFF;">&lt;/</span><span style="color:#F07178;">filter</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">filter-mapping</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">filter-name</span><span style="color:#89DDFF;">&gt;</span><span style="color:#A6ACCD;">HiddenHttpMethodFilter</span><span style="color:#89DDFF;">&lt;/</span><span style="color:#F07178;">filter-name</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">url-pattern</span><span style="color:#89DDFF;">&gt;</span><span style="color:#A6ACCD;">/*</span><span style="color:#89DDFF;">&lt;/</span><span style="color:#F07178;">url-pattern</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#89DDFF;">&lt;/</span><span style="color:#F07178;">filter-mapping</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"></span></code></pre></div><blockquote><p>注：</p><p>目前为止，SpringMVC 中提供了两个过滤器：CharacterEncodingFilter 和 HiddenHttpMethodFilter</p><p>在 web.xml 中注册时，必须先注册 CharacterEncodingFilter，再注册 HiddenHttpMethodFilter</p><p>原因：</p><ul><li>在 CharacterEncodingFilter 中通过 request.setCharacterEncoding(encoding) 方法设置字符集的</li><li>request.setCharacterEncoding(encoding) 方法要求前面不能有任何获取请求参数的操作</li><li>而 HiddenHttpMethodFilter 恰恰有一个获取请求方式的操作：</li><li></li></ul></blockquote><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#A6ACCD;">String paramValue = request.getParameter(this.methodParam);</span></span>
<span class="line"><span style="color:#A6ACCD;"></span></span></code></pre></div>`,25),r=[n];function p(o,d,i,c,h,F){return s(),e("div",null,r)}const D=t(l,[["render",p]]);export{u as __pageData,D as default};
